-- Run with Supabase CLI or SQL editor. All public tables have RLS enabled.
create type public.app_role as enum ('customer','admin');
create type public.unit_type as enum ('homestay','roomstay','whole_house');
create type public.booking_status as enum ('pending','awaiting_payment','payment_review','confirmed','checked_in','completed','cancelled','rejected','expired');
create type public.payment_status as enum ('unpaid','proof_uploaded','under_review','paid','failed','refunded','partially_refunded');
create table public.profiles (id uuid primary key references auth.users on delete cascade, full_name text, email text, phone text, role public.app_role not null default 'customer', avatar_url text, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.properties (id uuid primary key default gen_random_uuid(), name text not null, slug text unique not null, description text, address text, latitude numeric, longitude numeric, check_in_time time default '15:00', check_out_time time default '12:00', house_rules text, status text not null default 'active', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.units (id uuid primary key default gen_random_uuid(), property_id uuid not null references public.properties(id) on delete cascade, name text not null, slug text unique not null, unit_type public.unit_type not null, short_description text, description text, bedrooms integer not null default 1, bathrooms integer not null default 1, maximum_guests integer not null check(maximum_guests>0), base_price numeric(12,2) not null check(base_price>=0), cleaning_fee numeric(12,2) not null default 0, deposit_amount numeric(12,2) not null default 0, minimum_nights integer not null default 1, status text not null default 'active', created_at timestamptz default now(), updated_at timestamptz default now());
create table public.unit_relations (id uuid primary key default gen_random_uuid(), parent_unit_id uuid not null references public.units(id) on delete cascade, child_unit_id uuid not null references public.units(id) on delete cascade, unique(parent_unit_id,child_unit_id));
create table public.unit_images (id uuid primary key default gen_random_uuid(), unit_id uuid not null references public.units(id) on delete cascade, image_url text not null, alt_text text, sort_order integer not null default 0, is_cover boolean not null default false, created_at timestamptz default now());
create table public.amenities (id uuid primary key default gen_random_uuid(), name text unique not null, icon_name text, category text);
create table public.unit_amenities (unit_id uuid references public.units(id) on delete cascade, amenity_id uuid references public.amenities(id) on delete cascade, primary key(unit_id,amenity_id));
create table public.bookings (id uuid primary key default gen_random_uuid(), booking_number text unique not null, customer_id uuid not null references public.profiles(id), unit_id uuid not null references public.units(id), check_in_date date not null, check_out_date date not null, adult_count integer not null default 1, child_count integer not null default 0, subtotal numeric(12,2) not null, cleaning_fee numeric(12,2) not null default 0, deposit_amount numeric(12,2) not null default 0, discount_amount numeric(12,2) not null default 0, total_amount numeric(12,2) not null, booking_status public.booking_status not null default 'pending', payment_status public.payment_status not null default 'unpaid', special_request text, internal_note text, expires_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now(), check(check_out_date>check_in_date));
create table public.payments (id uuid primary key default gen_random_uuid(), booking_id uuid not null references public.bookings(id) on delete cascade, payment_method text not null default 'bank_transfer', amount numeric(12,2) not null check(amount>=0), reference_number text, receipt_path text, payment_status public.payment_status not null default 'unpaid', paid_at timestamptz, verified_by uuid references public.profiles(id), verified_at timestamptz, rejection_reason text, created_at timestamptz default now());
create table public.blocked_dates (id uuid primary key default gen_random_uuid(), unit_id uuid not null references public.units(id) on delete cascade, start_date date not null, end_date date not null, reason text, created_by uuid references public.profiles(id), created_at timestamptz default now(), check(end_date>=start_date));
create table public.seasonal_prices (id uuid primary key default gen_random_uuid(), unit_id uuid not null references public.units(id) on delete cascade, name text not null, start_date date not null, end_date date not null, price_per_night numeric(12,2) not null, minimum_nights integer default 1, created_at timestamptz default now());
create table public.promotions (id uuid primary key default gen_random_uuid(), code text unique not null, name text not null, discount_type text not null check(discount_type in ('percentage','fixed')), discount_value numeric not null, minimum_spend numeric default 0, start_at timestamptz, end_at timestamptz, usage_limit integer, status text default 'active');
create table public.reviews (id uuid primary key default gen_random_uuid(), booking_id uuid unique not null references public.bookings(id), customer_id uuid not null references public.profiles(id), unit_id uuid not null references public.units(id), rating integer not null check(rating between 1 and 5), comment text, status text not null default 'pending', created_at timestamptz default now());
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.profiles where id=(select auth.uid()) and role='admin') $$;
revoke all on function public.is_admin() from public; grant execute on function public.is_admin() to authenticated;
create or replace function public.is_unit_available(p_unit_id uuid,p_check_in date,p_check_out date) returns boolean language sql stable security definer set search_path=public as $$ select not exists(select 1 from public.bookings b where b.unit_id=p_unit_id and b.check_in_date<p_check_out and b.check_out_date>p_check_in and (b.booking_status in ('confirmed','checked_in','completed','payment_review') or (b.booking_status in ('pending','awaiting_payment') and b.expires_at>now())) and not exists(select 1 from public.blocked_dates d where d.unit_id=p_unit_id and d.start_date<p_check_out and d.end_date>=p_check_in) $$;
revoke all on function public.is_unit_available(uuid,date,date) from public; grant execute on function public.is_unit_available(uuid,date,date) to anon,authenticated;
alter table public.profiles enable row level security; alter table public.properties enable row level security; alter table public.units enable row level security; alter table public.unit_relations enable row level security; alter table public.unit_images enable row level security; alter table public.amenities enable row level security; alter table public.unit_amenities enable row level security; alter table public.bookings enable row level security; alter table public.payments enable row level security; alter table public.blocked_dates enable row level security; alter table public.seasonal_prices enable row level security; alter table public.promotions enable row level security; alter table public.reviews enable row level security;
create policy "public reads active properties" on public.properties for select to anon,authenticated using(status='active');
create policy "public reads active units" on public.units for select to anon,authenticated using(status='active');
create policy "public reads images" on public.unit_images for select to anon,authenticated using(true);
create policy "public reads amenities" on public.amenities for select to anon,authenticated using(true);
create policy "public reads approved reviews" on public.reviews for select to anon,authenticated using(status='approved');
create policy "customers read profile" on public.profiles for select to authenticated using(id=(select auth.uid()) or public.is_admin());
create policy "customers update profile" on public.profiles for update to authenticated using(id=(select auth.uid())) with check(id=(select auth.uid()) and role='customer');
create policy "customers read own bookings" on public.bookings for select to authenticated using(customer_id=(select auth.uid()) or public.is_admin());
create policy "customers create own booking" on public.bookings for insert to authenticated with check(customer_id=(select auth.uid()) and booking_status='pending' and payment_status='unpaid');
create policy "admins manage bookings" on public.bookings for all to authenticated using(public.is_admin()) with check(public.is_admin());
create policy "customers read own payments" on public.payments for select to authenticated using(exists(select 1 from public.bookings b where b.id=booking_id and (b.customer_id=(select auth.uid()) or public.is_admin())));
create policy "admins manage payments" on public.payments for all to authenticated using(public.is_admin()) with check(public.is_admin());
create policy "admins manage property data" on public.units for all to authenticated using(public.is_admin()) with check(public.is_admin());
create policy "admins manage blocks" on public.blocked_dates for all to authenticated using(public.is_admin()) with check(public.is_admin());
create policy "admins manage prices" on public.seasonal_prices for all to authenticated using(public.is_admin()) with check(public.is_admin());
create policy "customers submit completed review" on public.reviews for insert to authenticated with check(customer_id=(select auth.uid()) and exists(select 1 from public.bookings b where b.id=booking_id and b.customer_id=(select auth.uid()) and b.booking_status='completed'));
-- Create a private bucket named payment-receipts in the dashboard. Storage policies must restrict owner path booking_id/auth.uid().
